import './encounter.css';
import './encounter-ring.css';
import {
	CircularInput,
  CircularTrack,
  CircularThumb,
} from "react-circular-input";

import encounter from './encounters.json'
export default function Encounter({ hideEncounterComponent }) {
	let storedEncounterID = localStorage.getItem('encounterID');
	let encounterID = 0;

	if (storedEncounterID !== null) {
	  encounterID = parseInt(storedEncounterID); // Parse the stored value to an integer
	}

	// Check if the encounterID is a valid index in the encounter array
	if (
	  encounter &&
